const body = items[0].json.body || items[0].json;

const paymentStatus = body.payment_status || '';
const tokenCode = body.custom_str1 || '';
const email = body.custom_str2 || '';
const pfPaymentId = body.pf_payment_id || '';
const amountGross = body.amount_gross || '0';

return [{
  json: {
    payment_status: paymentStatus,
    token_code: tokenCode,
    email,
    pf_payment_id: pfPaymentId,
    amount_gross: amountGross,
    is_complete: paymentStatus === 'COMPLETE'
  }
}];
